    async markNotificationRead(notificationId) {
        if (!notificationId) return null;
        const request = {
            path: PRIVATE_POST_NOTIFICATION_READ,
            body: {
                notification_id: notificationId,
            },
        }
        const resp = await this.sendToNode(request);

        // Optimistic local update so the SideNav badge ticks down
        // without waiting for the next poll. Flip the matching
        // notification's is_read and decrement unread_count.
        const target = latestNotifications.notifications.find(n => n && n.id === notificationId);
        if (target && !target.is_read) {
            target.is_read = true;
            latestNotifications = {
                unread_count: Math.max(0, (latestNotifications.unread_count || 1) - 1),
                notifications: latestNotifications.notifications,
            };
            for (const cb of notificationSubscribers) {
                cb(latestNotifications);
            }
        }
        return resp;
    },

    // markAllNotificationsRead flips every unread notification on the node
    // in one request. Marking page-by-page from the client only ever
    // covered the first page, so unread items beyond it kept the badge
    // alive forever.
    async markAllNotificationsRead() {
        const resp = await this.sendToNode({
            path: PRIVATE_POST_NOTIFICATIONS_READ,
            body: {},
        });

        // Optimistic local update so the SideNav badge clears without
        // waiting for the next poll.
        latestNotifications = {
            unread_count: 0,
            notifications: latestNotifications.notifications.map(
                n => n && !n.is_read ? { ...n, is_read: true } : n
            ),
        };
        for (const cb of notificationSubscribers) {
            cb(latestNotifications);
        }
        return resp;
    },

    subscribeNotifications(callback) {
        notificationSubscribers.add(callback);
        callback(latestNotifications);
        return () => {
            notificationSubscribers.delete(callback);
        };
    },

